-- ============================================================================
-- 2025 黑龙江一分一段表 + 志愿数 seed
--
-- 数据来源：https://www.dxsbb.com/news/100879.html (2025-06-24 发布)
-- 物理类 117,407 人；历史类 54,707 人
--
-- Idempotent：可重跑（ON CONFLICT UPDATE）。
--
-- 使用方式：
--   docker-compose exec -T db psql -U app -d admission \
--     < admission-api/scripts/seed_2025_hlj_score_rank.sql
-- ============================================================================

BEGIN;

-- ---------------------------------------------------------------------------
-- region_plan_size_map：2025 年黑龙江物理/历史 各 40 个院校专业组
-- ---------------------------------------------------------------------------
ON CONFLICT (year, region_code, subject_category_code) DO UPDATE
SET plan_size = EXCLUDED.plan_size,
    note = EXCLUDED.note,
    updated_at = NOW();

-- ---------------------------------------------------------------------------
-- score_rank_map：物理类 (2025, 230000, physics)
-- ---------------------------------------------------------------------------
ON CONFLICT (year, region_code, subject_category_code, score) DO UPDATE
SET cumulative_rank = EXCLUDED.cumulative_rank;

-- ---------------------------------------------------------------------------
-- score_rank_map：历史类 (2025, 230000, history)
-- ---------------------------------------------------------------------------
ON CONFLICT (year, region_code, subject_category_code, score) DO UPDATE
SET cumulative_rank = EXCLUDED.cumulative_rank;

-- ---------------------------------------------------------------------------
-- 验证：累计人数最大值应该等于该类别总人数（物理 117407 / 历史 54707）
-- ---------------------------------------------------------------------------
DO $$
DECLARE
    physics_max INTEGER;
    history_max INTEGER;
    physics_count INTEGER;
    history_count INTEGER;
BEGIN
    SELECT MAX(cumulative_rank), COUNT(*)
      INTO physics_max, physics_count
      FROM score_rank_map
     WHERE year = 2025 AND region_code = '230000' AND subject_category_code = 'physics';

    SELECT MAX(cumulative_rank), COUNT(*)
      INTO history_max, history_count
      FROM score_rank_map
     WHERE year = 2025 AND region_code = '230000' AND subject_category_code = 'history';

    RAISE NOTICE '2025 HLJ physics: rows=%, max_rank=% (expected 117407)', physics_count, physics_max;
    RAISE NOTICE '2025 HLJ history: rows=%, max_rank=% (expected 54707)', history_count, history_max;

    IF physics_max != 117407 THEN
        RAISE EXCEPTION 'physics max rank mismatch: got %, want 117407', physics_max;
    END IF;
    IF history_max != 54707 THEN
        RAISE EXCEPTION 'history max rank mismatch: got %, want 54707', history_max;
    END IF;
END $$;

COMMIT;
